package org.jaa.bandwidthtester;


/**
 *
 * @author jerry
 */
@SuppressWarnings("unused")
public class TerminalType
{
    public  String ANSI_LINE                   = "─";
    public  String BOTTOM_LEFT_CORNER          = "└";
    public  String BOTTOM_RIGHT_CORNER         = "┘";
    public  String LEFT_COLUMN_LINE            = "├";
    public  String RIGHT_COLUMN_LINE           = "┤";
    public  String TOP_LEFT_CORNER             = "┌";
    public  String TOP_RIGHT_CORNER            = "┐";
    public  String VERTICAL_BAR                = "│";
    public String FANCY_RIGHT_ARROW            = "\ue0b4";
    public String FANCY_LEFT_ARROW             = "\ue0b6";

    private TERM m_term;
    private boolean m_utf;


    protected enum TERM {ANSI, DUMB}

    TerminalType()
    {
        m_term = TERM.ANSI;
        m_utf = true;


        String termEnv = System.getenv("TERM");
        if (termEnv == null) termEnv = System.getProperty("TERM");
        String lang = System.getenv("LANG");
        if (lang == null) lang = System.getProperty("LANG");     
        if ((termEnv == null) || termEnv.isEmpty() || termEnv.equalsIgnoreCase("dumb")) {
            m_term = TERM.DUMB;
        }
        if ((lang == null) || !lang.toLowerCase().contains("utf")) {
            m_utf = false;
        }

        // Windows has special Handling and escape sequence processing
        if (OS.getMyOS() == OS.OSTypes.WINDOWS) {
            m_utf = true;
            m_term = TERM.ANSI;
        }

        if (!m_utf) {
            VERTICAL_BAR = "|";
            BOTTOM_LEFT_CORNER = "+";
            BOTTOM_RIGHT_CORNER = "+";
            TOP_LEFT_CORNER = "+";
            TOP_RIGHT_CORNER = "+";
            LEFT_COLUMN_LINE = "+";
            RIGHT_COLUMN_LINE = "+";
            ANSI_LINE = "-";
            FANCY_RIGHT_ARROW=")";
            FANCY_LEFT_ARROW="(";
        }
    }



    public boolean isAnsiTerm()                          { return (m_term == TERM.ANSI);   }
    public boolean isUTF()                               { return m_utf;                   }
    @SuppressWarnings("ClassEscapesDefinedScope")
    public TERM getTerm()                                { return this.m_term;             }

}

package org.jaa.bandwidthtester;

import java.util.Date;

public class ResultDetails {
    String min = "N/A";
    String max = "N/A";
    String avg = "N/A";
    int rc = -1;
    Date runDate = new Date();

    public ResultDetails() {}

    @Override
    public String toString() {

        return String.format("Result=%d, min=%s, max=%s, avg=%s", rc, min, max, avg);
    }


    public void setMin(String min) { this.min = min; }
    public void setMax(String max) { this.max = max; }
    public void setAvg(String avg) { this.avg = avg; }
    public void setRc(int rc)      { this.rc = rc;   }
    public Date getRunDate()       { return runDate; }
    public int getRc()             { return rc;      }
    public void setRunDate(Date runDate) { this.runDate = runDate; }
    public String getMin()         { return min;     }
    public String getMax()         { return max;     }
    public String getAvg()         { return avg;     }

}

package org.jaa.bandwidthtester;


import com.sun.jna.Function;
import com.sun.jna.platform.win32.WinDef.BOOL;
import com.sun.jna.platform.win32.WinDef.DWORD;
import com.sun.jna.platform.win32.WinDef.DWORDByReference;
import com.sun.jna.platform.win32.WinDef.UINT;
import com.sun.jna.platform.win32.WinDef.UINTByReference;
import com.sun.jna.platform.win32.WinNT.HANDLE;

import java.io.FileDescriptor;
import java.io.FileOutputStream;
import java.io.PrintStream;
import java.nio.charset.StandardCharsets;

/**
 *
 * @author jerry
 */
public final class OS
{
    @SuppressWarnings("unused")
    protected enum OSTypes
    {
        LINUX,
        MAC,
        WINDOWS,
        UNKNOWN
    }

    private static OSTypes myOS;

    private OS()
    {
        String os = System.getProperty("os.name");
      //  System.out.printf("os = '%s'\n", os);
        switch (os.toLowerCase().substring(0, 3))
        {
            case "mac":
                myOS = OSTypes.MAC;
                break;
            case "lin":
                myOS = OSTypes.LINUX;
                break;
            case "win":
                myOS = OSTypes.WINDOWS;
                break;
            default:
                myOS = OSTypes.UNKNOWN;
                break;
        }
    }

    @SuppressWarnings("ClassEscapesDefinedScope")
    public static OSTypes getMyOS() {
        return myOS;
    }


    /**
     * On Windows, in order to get ANSI escape sequence colors, and some other
     * required terminal output, we resort to calling into
     * Following documented APIs from:
     *    Console Developer's guide & API Reference - 05/18/2021
     *       <li></li><a href="https://learn.microsoft.com/en-us/windows/console/setconsolemode">...</a></li>
     *       <li></li><a href="https://learn.microsoft.com/en-us/windows/console/setconsoleoutputcp">...</a></li>
     *
     * @param myArgs - Arguments from command-line
     */
    public static void setWindowsConsoleMode(Args myArgs) {
        if (myArgs.verbose) System.out.printf("setting Windows Console Mode: myOS.getMyOS() = '%s' ? ", getMyOS());
        if (myOS == OSTypes.WINDOWS) {
            if (myArgs.verbose) System.out.println("YES");
            try {
                // Set output mode to handle virtual terminal sequences
                try {
                    if (myArgs.verbose) System.out.println("On Windows we are forcing Java to use UTF");
                    System.setOut(new PrintStream(new FileOutputStream(FileDescriptor.out), true, StandardCharsets.UTF_8));
                } catch (Exception e) {
                    System.out.println("Cannot properly set  Windows Code Page to UTF, output may be garbled!");
                }
                Function GetStdHandleFunc  = Function.getFunction("kernel32", "GetStdHandle");
                DWORD    STD_OUTPUT_HANDLE = new DWORD(-11);
                HANDLE   hOut              = (HANDLE) GetStdHandleFunc.invoke(HANDLE.class, new Object[]{STD_OUTPUT_HANDLE});

                DWORDByReference p_dwMode           = new DWORDByReference(new DWORD(0));
                Function         GetConsoleModeFunc = Function.getFunction("kernel32", "GetConsoleMode");
                GetConsoleModeFunc.invoke(BOOL.class, new Object[]{hOut, p_dwMode});

                int   ENABLE_VIRTUAL_TERMINAL_PROCESSING = 4;
                DWORD dwMode                             = p_dwMode.getValue();
                dwMode.setValue(dwMode.intValue() | ENABLE_VIRTUAL_TERMINAL_PROCESSING);
                Function SetConsoleModeFunc = Function.getFunction("kernel32", "SetConsoleMode");
                SetConsoleModeFunc.invoke(BOOL.class, new Object[]{hOut, dwMode});

                if (myArgs.verbose) System.out.println("And now we force Windows to also use the Code Page for UTF");
                UINTByReference p_wCodePageID = new UINTByReference(new UINT(0));
                UINT wCodePageID           = p_wCodePageID.getValue();
                wCodePageID.setValue(65001);
                Function SetConsoleOutputCP  = Function.getFunction("kernel32", "SetConsoleOutputCP");
                SetConsoleOutputCP.invoke(BOOL.class, new Object[]{wCodePageID});

            } catch (NoClassDefFoundError ne) {
                System.out.println("Running on Windows without console mode, characters can be garbled.");
            }
        } else {
            if (myArgs.verbose) System.out.println("NO");
        }
    }

}

