package org.jaa.bandwidthtester;

/**
 *
 * @author jerry
 */
public class ConnectionDetails {

    private static final double kb = 1024.0;
    private static final double mb = kb * kb;
    private static final double gb = kb * mb;
    private static final double tb = kb * gb;

    private String minColor = "";
    private String maxColor = "";
    private String defaultUnitFormat = "  %-10.10s  ";
    private String defaultValFormat = " %,8.2f";
    private boolean isColored = true;

    public void disableColors() {
        minColor = "";
        maxColor = "";
        defaultUnitFormat = " %s";
        defaultValFormat = "%.2f";
        isColored = false;
    }

    public void enableColors() {
        minColor = AnsiCodes.ANSI_COLOR.RED.getReverseBoldCode(m_myArgs.getTermType());
        maxColor = AnsiCodes.ANSI_COLOR.BLUE.getReverseBoldCode(m_myArgs.getTermType());
        defaultUnitFormat = "  %-10.10s  ";
        defaultValFormat = " %,8.2f";
        isColored = true;
    }
    private   String   m_localHost       = "";
    private   String   m_remoteHost      = "";
    private   int      m_localPort       = -1;
    private   int      m_remotePort      = -1;
    private   int      m_timePeriod      = 0;
    private   int      m_resultEntry     = 0;
    private   boolean  m_gathered        = false;
    private   boolean  m_summaryResults  = false;
    private   boolean  m_singleThread    = false;
    protected double   m_maxBytesPerSec  = Double.MIN_VALUE;
    protected double   m_minBytesPerSec  = Double.MAX_VALUE;
    protected double   m_maxBitsPerSec   = Double.MIN_VALUE;
    protected double   m_minBitsPerSec   = Double.MAX_VALUE;
    protected boolean  m_isBytesUnit     = true;
    private   boolean  m_verbose         = false;
    private   boolean  m_lastOmitted     = false;
    private ResultDetails m_resultDetails = new ResultDetails();
    private final Args m_myArgs;

    public ResultDetails getResultDetails()                   { return m_resultDetails;          }
    public void setResultDetails(ResultDetails resultDetails) { m_resultDetails = resultDetails; }


    public boolean isLastOmitted()    { return m_lastOmitted;           }

    public boolean isVerbose()        { return m_verbose;               }
    public boolean isGathered()       { return m_gathered;              }
    public boolean isSingleThread()   { return m_singleThread;          }
    public boolean isFinished()       { return (m_resultEntry != -999); }
    public boolean isSummaryResults() { return m_summaryResults;        }
    public String  getLocalHost()     { return m_localHost;             }
    public int     getRemotePort()    { return m_remotePort;            }
    public int     getLocalPort()     { return m_localPort;             }
    public int     getTimePeriod()    { return m_timePeriod;            }
    public String  getRemoteHost()    { return m_remoteHost;            }
    public int     getResultEntry()   { return m_resultEntry;           }
    public String getDefaultUnitFormat() { return defaultUnitFormat;    }
    public String getDefaultValFormat()  { return defaultValFormat;     }
    public boolean isColored()           { return isColored;            }


    /**
     * Constructor
     * @param args Command line arguments
     */
    public ConnectionDetails(Args args) {
        m_myArgs = args;
        enableColors();
    }

    public String getMinBitsBytesPerSec() {
        String result = "N/A";
        if (m_isBytesUnit) {
            if (m_minBytesPerSec != Double.MAX_VALUE) {
                result = String.format("%s%s",
                                       minColor,
                                       convertToHumanReadable(m_myArgs, m_minBytesPerSec, true,
                                                              getDefaultUnitFormat(), getDefaultValFormat(),
                                                              isColored()));
            }
        } else {
            if (m_minBitsPerSec != Double.MAX_VALUE) {
                result = String.format("%s%s",
                                       minColor,
                                       convertToHumanReadable(m_myArgs, m_minBitsPerSec, false,
                                                              getDefaultUnitFormat(), getDefaultValFormat(),
                                                              isColored()));
            }
        }

        return result;
    }
    public String getMaxBitsBytesPerSec() {
        String result = "N/A";
        if (m_isBytesUnit) {
            if (m_maxBytesPerSec != Double.MIN_VALUE) {
                result = String.format("%s%s",
                                       maxColor,
                                       convertToHumanReadable(m_myArgs, m_maxBytesPerSec, true,
                                                              getDefaultUnitFormat(), getDefaultValFormat(),
                                                              isColored()));
            }
        } else {
            if (m_maxBitsPerSec != Double.MIN_VALUE) {
                result = String.format("%s%s",
                                       maxColor,
                                       convertToHumanReadable(m_myArgs, m_maxBitsPerSec, false,
                                                              getDefaultUnitFormat(), getDefaultValFormat(),
                                                              isColored()));
            }
        }
        return result;
    }

    public void setMaxBitsBytesPerSec(double value, String unit)  {
        double[] converted = convertUnitToBitsAndBytes(value, unit);
        double maxBitsPerSec = converted[0];
        double maxBytesPerSec = converted[1];
        if (!m_isBytesUnit) {
            if (isVerbose()) System.out.printf("\tsetMaxBitsPerSec(%.2f %s): [current max bits/sec = %.0f] ",
                                               value, unit,
                                               ((m_maxBitsPerSec != Double.MIN_VALUE) ? m_maxBitsPerSec : -1));
            if (maxBitsPerSec != -1 && maxBitsPerSec > m_maxBitsPerSec) {
                if (isVerbose()) System.out.printf(" [Setting maxBitsPerSec to %.0f bits/sec (orig = %s)] ", maxBitsPerSec, unit);
                m_maxBitsPerSec = maxBitsPerSec;
            }
        } else {
            if (isVerbose()) System.out.printf("\tsetMaxBytesPerSec(%.2f %s): [current max bytes/sec = %.0f] ",
                                               value, unit,
                                               ((m_maxBytesPerSec != Double.MIN_VALUE) ? m_maxBytesPerSec : -1));

            if (maxBytesPerSec != -1 && maxBytesPerSec > m_maxBytesPerSec) {
                if (isVerbose()) System.out.printf(" [Setting maxBytesPerSec to %.0f bytes/sec (orig = %s)] ", maxBytesPerSec, unit);
                m_maxBytesPerSec = maxBytesPerSec;
            }
        }
        if (isVerbose()) System.out.println();
    }

    public void setMinBitsBytesPerSec(double value, String unit)  {

        double[] converted = convertUnitToBitsAndBytes(value, unit);
        double minBitsPerSec = converted[0];
        double minBytesPerSec = converted[1];
        if (!m_isBytesUnit) {
            if (isVerbose()) System.out.printf("\tsetMinBitsPerSec(%.2f %s): [current min bits/sec = %.0f] ",
                                               value, unit,
                                               ((m_minBitsPerSec != Double.MAX_VALUE) ? m_minBitsPerSec : -1));
            if (minBitsPerSec != -1 && minBitsPerSec < m_minBitsPerSec) {
                if (isVerbose()) System.out.printf(" [Setting minBitsPerSec to %.0f bits/sec (orig = %s)] ", minBitsPerSec, unit);
                m_minBitsPerSec = minBitsPerSec;
            }
        } else {
            if (isVerbose()) System.out.printf("\tsetMinBytesPerSec(%.2f %s): [current min bytes/sec = %.0f] ",
                                               value, unit,
                                               ((m_minBytesPerSec != Double.MAX_VALUE) ? m_minBytesPerSec : -1));
            if (minBytesPerSec != -1 && minBytesPerSec < m_minBytesPerSec) {
                if (isVerbose()) System.out.printf(" [Setting minBytesPerSec to %.0f bytes/sec (orig = %s)] ", minBytesPerSec, unit);
                m_minBytesPerSec = minBytesPerSec;
            }
        }
        if (isVerbose()) System.out.println();
    }

    private double[] convertUnitToBitsAndBytes(double value, String unit) {
        double[] result = new double[2];
        double bits = -1;
        double bytes = -1;
        switch (unit.trim().toLowerCase()) {
            case "bytes/sec":  bytes = value; break;
            case "kbytes/sec": bytes = value * kb; break;
            case "mbytes/sec": bytes = value * mb; break;
            case "gbytes/sec": bytes = value * gb; break;
            case "tbytes/sec": bytes = value * tb; break;

            case "bits/sec":  bits = value;      m_isBytesUnit = false; break;
            case "kbits/sec": bits = value * kb; m_isBytesUnit = false; break;
            case "mbits/sec": bits = value * mb; m_isBytesUnit = false; break;
            case "gbits/sec": bits = value * gb; m_isBytesUnit = false; break;
            case "tbits/sec": bits = value * tb; m_isBytesUnit = false; break;
            default:
                throw new IllegalArgumentException("Invalid unit: " + unit);
        }
        result[0] = bits;
        result[1] = bytes;
        return result;
    }

    public static String convertToHumanReadable(Args args, double val, boolean bitsOrBytes, String fmt1, String fmt2, boolean isColor) {
        if (args.isDebug()) System.out.printf("Normalizing val = %,f, kb = %,f\n", val, kb);
        if (val <= 0) {
            if (isColor) return ("- - - - -" + AnsiCodes.getReset(args.getTermType()));
            else return "STALLED";
        }
        String tbString = "Tbits";
        String gbString = "Gbits";
        String mbString = "Mbits";
        String kbString = "Kbits";
        String bString = "bits";
        if (bitsOrBytes) {
            // Tbytes/sec
            // 1234567890
            tbString = "TBytes";
            gbString = "GBytes";
            mbString = "MBytes";
            kbString = "KBytes";
            bString = "Bytes";
        }
        double tbVal = val / tb;
        double gBVal = val / gb;
        double mBVal = val / mb;
        double kBVal = val / kb;

        String unitString;
        double valUnits;
        if (tbVal > 1.0) {
            valUnits = tbVal;
            unitString = tbString;
        } else if (gBVal > 1.0) {
            valUnits = gBVal;
            unitString = gbString;
        } else if (mBVal > 1.0) {
            valUnits = mBVal;
            unitString = mbString;
        } else if (kBVal > 1.0) {
            valUnits = kBVal;
            unitString = kbString;
        } else {
            valUnits = val;
            unitString = bString;
        }
        unitString += "/sec";
        return String.format(fmt2 + "%s%s" + fmt1 + "%s",
                             valUnits,
                             AnsiCodes.getReset(args.getTermType()),
                             AnsiCodes.getBold(args.getTermType()),
                             unitString,
                             AnsiCodes.getReset(args.getTermType()));

    }


    public void setLastOmitted(boolean lastOmitted)       { m_lastOmitted = lastOmitted;       }
    public void setVerbose(boolean verbose)               { m_verbose = verbose;               }
    public void setGathered(boolean gathered)             { m_gathered = gathered;             }
    public void setTimePeriod(int timePeriod)             { m_timePeriod = timePeriod;         }
    public void setSummaryResults(boolean summaryResults) { m_summaryResults = summaryResults; }
    public void setLocalHost(String localHost)            { m_localHost = localHost;           }
    public void setRemoteHost(String remoteHost)          { m_remoteHost = remoteHost;         }
    public void setIsSingleThread(boolean singleThread)   { m_singleThread = singleThread;     }
    public void setResultEntry(int resultEntry)           { m_resultEntry = resultEntry;       }
    public void incrementResultEntry()                    { m_resultEntry++;                   }
    public void setFinished()                             { m_resultEntry = -999;              }    
    public void setLocalPort(String localPort) { 
        try {
            m_localPort = Integer.parseInt(localPort);
        } catch (NumberFormatException n) {
            m_localPort = -1;
        }
    }

    public void setRemotePort(String remotePort) { 
        try {
            m_remotePort = Integer.parseInt(remotePort);
        } catch (NumberFormatException n) {
            m_remotePort = -1;
        }
    }




}

package org.jaa.bandwidthtester;

import java.io.File;
import java.io.IOException;
import java.io.PrintStream;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.util.*;

/**
 *
 * @author jerry
 */
public class BandwidthTester {
    private static final String[] iperf3Executables = {
            "/usr/jaalocal/bin/iperf3",
            "/usr/local/bin/iperf3",
            "/usr/bin/iperf3",
            "/bin/iperf3",
            "/opt/local/bin/iperf3",
            "C:/Program Files/iperf3.17.1_64/iperf3.exe",
            "C:/Program Files/iperf3-3.17.1_64/iperf3.exe",
            "C:/Program Files/iperf3.12_64/iperf3.exe",
            "C:/Program Files/iperf-3.1.3-win64/iperf3.exe"};

    private static final List<ResultDetails> averageResults = new ArrayList<>();
    private static TerminalType termType = null;
    private static Args myArgs = null;
    private static boolean cleanExit = false;

    /**
     * @return find the preferred iperf3 executable
     */
    private static String findIPerf3() {
        String ip = null;
        for (String exe : iperf3Executables) {
            File f = new File(exe);
            if (f.exists() && f.canExecute()) {
                ip = exe;
                break;
            }
        }
        if (ip == null) {
            System.out.println("Cannot find iperf3!");
            System.exit(1);
        }
        return ip;
    }


    /**
     * @param myArgs Command-line arguments
     * @param noBuffer whether to use buffering (iperf3 will not buffer output)
     * @return command-line arguments for iperf3
     */
    private static String[] prepareIPerfExe(Args myArgs, boolean noBuffer) {
        List<String> args = new ArrayList<>();
        String[] ret = {
                findIPerf3(),
                (!noBuffer ? "--forceflush" : ""),
                (!noBuffer ? "--connect-timeout" : ""),
                (!noBuffer ? "3000" : ""),
                "-c",
                myArgs.client,
                myArgs.omit,
                myArgs.parallel,
                "-t",
                Integer.toString(myArgs.times),
                (myArgs.reverse ? "-R" : ""),
        };
        args.addAll(Arrays.asList(ret));
        args.addAll(Arrays.asList(myArgs.getRemainingArgs()));
        return args.toArray(new String[0]);
    }


    public static void main(String[] args) {
        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            if (!cleanExit) System.out.println("\n\033[31mShutdown hook ran\033[0m!");
        }));

        termType = new TerminalType();
        myArgs = processArgs(args);
        if (myArgs.client.isEmpty()) {
            System.out.print("Must supply iperf3 server name: ");
            Scanner sc = new Scanner(System.in);
            myArgs.client = sc.nextLine();
            if (myArgs.client.isEmpty()) {
                usage();
                return;
            }
        }

        myArgs.setTermType(termType);
        OS.setWindowsConsoleMode(myArgs);
        int rc = -999;


        String[] iperf3cmdLine = prepareIPerfExe(myArgs, false);


        if (myArgs.repeat == 0) {
            System.out.printf("\n[%s%s%s]%s%15.15s%s%s: ",
                              AnsiCodes.ANSI_COLOR.GREEN.getReverseBoldCode(myArgs.getTermType()),
                              new Date(),
                              AnsiCodes.getReset(myArgs.getTermType()),
                              AnsiCodes.ANSI_COLOR.PURPLE.getReverseBoldCode(myArgs.getTermType()),
                              "                                        ",
                              "Executing",
                              AnsiCodes.getReset(myArgs.getTermType()));
            ResultDetails resultDetails = new ResultDetails();
            rc = IPerf3Monitor.run(iperf3cmdLine, myArgs, resultDetails, true);
            if (rc == 999) {
                iperf3cmdLine = prepareIPerfExe(myArgs, true);
                IPerf3Monitor.run(iperf3cmdLine, myArgs, resultDetails, true);
            }

        } else {
            int loop = 0;

            while (loop < myArgs.getRepeat()) {
                boolean showOutput = (loop == 0);
                Date currentDate = new Date();
                System.out.printf("\n[%s%s%s]%s%15.15s%s%d%s%d%40.40s%s: ",
                                  AnsiCodes.ANSI_COLOR.GREEN.getReverseBoldCode(myArgs.getTermType()),
                                  currentDate,
                                  AnsiCodes.getReset(myArgs.getTermType()),
                                  AnsiCodes.ANSI_COLOR.PURPLE.getReverseBoldCode(myArgs.getTermType()),
                                  "                                        ",
                                  "Execution #",
                                  loop + 1,
                                  " of ",
                                  myArgs.repeat,
                                  "                                                            ",
                                  AnsiCodes.getReset(myArgs.getTermType()));
                ResultDetails resultDetails = new ResultDetails();
                rc = IPerf3Monitor.run(iperf3cmdLine, myArgs, resultDetails, showOutput);
                if (rc == -999) {
                    iperf3cmdLine = prepareIPerfExe(myArgs, true);
                    continue;
                }
                loop++;
                resultDetails.setRunDate(currentDate);
                averageResults.add(resultDetails);
                System.out.print("  ");
                MonitorIPerf3Output.printLine(myArgs, 78);
                if (loop < (myArgs.getRepeat())) {
                    System.out.print("pause between runs: 2 seconds ... ");
                    try { //noinspection BusyWait
                        Thread.sleep(2000); } catch (InterruptedException ignored) { /**/ }
                    System.out.println("Done.");
                }
            }
        }
        displayResults();
        cleanExit = true;
        System.exit(rc);
    }


    private static void displayResults() {
        if (termType == null || myArgs == null || averageResults.isEmpty()) return;
        Path resultsFile = Paths.get("results.txt");
        try (PrintStream out = new PrintStream(Files.newOutputStream(resultsFile))) {
            System.out.printf("\n\n%sResults%s:  [\n",
                              AnsiCodes.ANSI_COLOR.PURPLE.getReverseBoldCode(myArgs.getTermType()),
                              AnsiCodes.getReset(myArgs.getTermType()));
            out.println("\n\nResults:  [");
            for (int i = 0; i < averageResults.size(); i++) {
                ResultDetails r = averageResults.get(i);
                String color = AnsiCodes.ANSI_COLOR.RED.getCode(myArgs.getTermType());
                if (r.getRc() == 0) color = AnsiCodes.ANSI_COLOR.GREEN.getCode(myArgs.getTermType());
                String returnString = ((r.getRc() == 0) ? "OK" : ("Error=" + r.getRc()));
                LocalDateTime localDateTime = r.getRunDate().toInstant().atZone(java.time.ZoneId.systemDefault()).toLocalDateTime();
                String isoDate = localDateTime.format(DateTimeFormatter.ISO_LOCAL_DATE_TIME);
                out.printf("\t    {%19.19s} => %s [%s]",
                                  isoDate,
                                  returnString,
                                  r);


                System.out.printf("\t    {%s%19.19s%s} => %s%s%s [%s%s%s]",
                                  AnsiCodes.ANSI_COLOR.BLUE.getCode(myArgs.getTermType()),
                                  isoDate,
                                  AnsiCodes.getReset(myArgs.getTermType()),
                                  color,
                                  returnString,
                                  AnsiCodes.getReset(myArgs.getTermType()),
                                  AnsiCodes.getBold(myArgs.getTermType()),
                                  r,
                                  AnsiCodes.getReset(myArgs.getTermType()));

                if (i < averageResults.size() - 1) { System.out.print(", "); }
                System.out.println();
                out.println();
            }
            System.out.print("\n\t  ]\n");
            out.print("\n\t  ]\n");
            averageResults.clear();
            System.out.printf("Output is saved to file: %s%s%s\n",
                              AnsiCodes.ANSI_COLOR.BLUE.getCode(myArgs.getTermType()),
                              resultsFile.toAbsolutePath(),
                              AnsiCodes.getReset(myArgs.getTermType()));
        } catch (IOException e) {
            System.err.printf("Error writing to %s: %s\n",  resultsFile.toAbsolutePath(), e.getMessage());
        }
    }

    private static Args processArgs(String[] a) {

        Args args = new Args();
        args.client = "";
        args.omit = "-O 2";
        args.parallel = "-P 8";
        args.times = 10;
        int argc = 0;
        while (argc < a.length) {
            String arg = a[argc];
            String argVal = null;
            if (argc < a.length - 1) {
                argVal = a[argc+1];
            }
            if (!arg.startsWith("-") && argc == 0) {
                args.client = arg;
            } else {
                String argSwitch = arg;
                if (arg.length() > 2) {
                    argSwitch = arg.substring(0,2);
                }
                switch (argSwitch) {
                    case "-R":
                        args.reverse = true;
                        break;
                    case "-O":
                        if (arg.length() > 2) {
                            args.omit = arg;
                        } else {
                            if (argVal != null) {
                                args.omit = "-O " + argVal;
                                argc++;
                            } else {
                                usage();
                            }
                        }
                        break;
                    case "-c":
                        if (arg.length() > 2) {
                            args.client = arg.substring(2);
                        } else {
                            if (argVal != null) {
                                args.client = argVal;
                                argc++;
                            } else {
                                usage();
                            }
                        }
                        break;
                    case "-P":
                        if (arg.length() > 2) {
                            args.parallel = arg;
                            if (arg.substring(2).equals("1")) {
                                args.single = true;
                            }
                        } else {
                            if (argVal != null) {
                                if (argVal.equals("1")) {
                                    args.single = true;
                                }
                                args.parallel = "-P " + argVal;
                                argc++;                        
                            } else {
                                usage();
                            }
                        }
                        break;
                    case "-t":
                        if (arg.length() > 2) {
                            try {
                                args.times = Integer.parseInt(arg.substring(2));
                            } catch (NumberFormatException ne) {
                                System.out.printf("Invalid numeric format for '-t': %s\n", arg);
                                usage();
                            }
                        } else {
                            if (argVal != null) {
                                try {
                                    args.times = Integer.parseInt(argVal);
                                    argc++;
                                } catch (NumberFormatException e) {
                                    System.out.printf("Invalid numeric format for '-t': %s\n", argVal);
                                    usage();
                                }
                            } else {
                                usage();
                            }
                        }
                        break;
                    case "-l":
                        if (arg.length() > 2) {
                            try {
                                args.repeat = Integer.parseInt(arg.substring(2));
                            } catch (NumberFormatException ne) {
                                System.out.printf("Invalid numeric format for '-l': %s\n", arg);
                                usage();
                            }
                        } else {
                            if (argVal!= null) {
                                try {
                                    args.repeat = Integer.parseInt(argVal);
                                } catch (NumberFormatException e) {
                                    System.out.printf("Invalid numeric format for '-l': %s\n", argVal);
                                    usage();
                                }
                            } else {
                                usage();
                            }
                            argc++;
                        }
                        break;
                    case "-v":
                        args.verbose=true;
                        break;
                    case "-d":
                        args.debug=true;
                        args.verbose=true;
                        break;
                    default:
                        args.remainingArgs.append(arg).append(" ");
                        break;
                }
            }
            argc++;
        }
        return args;
    }

    private static void usage() {
        System.out.println("Bad command-line arguments!");
        System.exit(1);
    }
}

